#include <bits/stdc++.h>using namespace std; // macros#define ll long long#define yes cout << "YES\n"#define no cout << "NO\n"#define f(i, size) for (int i = 0; i < size; i++)// #define ia(a, n) \//     int a[n];     \//     f(i, n) cin >> a[i] #define iv(v, n)     \    vector<ll> v(n); \    f(i, n) cin >> v[i] // #define M (1000000007)#define INF 1000000000000000000LL#define mp make_pair#define mt make_tuple #define nline '\n'#define pb push_back#define pii pair<int, int>#define pll pair<ll, ll>#define vii vector<pair<int, int>> void solve() {    ll n, k;    cin >> n >> k;     vector<ll> a(n + 2), p(k + 2);     for (ll i = 1; i <= n; i++) cin >> a[i];    for (ll i = 1; i <= k; i++) cin >> p[i];     p[0] = 0;    p[k + 1] = n + 1;     a[0] = a[n + 1] = a[p[1]];     ll sum = 0, mx = 0;     for (ll i = 0; i <= k; i++) {        ll ct = 0;         for (ll j = p[i]; j < p[i + 1]; j++) {            if (a[j] != a[j + 1]) ct++;        }         sum += ct;        mx = max(mx, ct);    }     cout << max(sum / 2, mx) << nline;}  int main(){    ios::sync_with_stdio(false);    cin.tie(nullptr);    cout.tie(nullptr);     ll t;    cin >> t;    while (t--) {        solve();    }    return 0;}